import { geo, geoFromHeaders, isInRegion, geoDistance } from './geo'

describe('geo', () => {
  describe('geo()', () => {
    it('should extract geo from Vercel headers', () => {
      const headers = new Headers({
        'x-vercel-ip-city': 'San Francisco',
        'x-vercel-ip-country': 'US',
        'x-vercel-ip-country-region': 'CA',
        'x-vercel-ip-latitude': '37.7749',
        'x-vercel-ip-longitude': '-122.4194',
        'x-vercel-ip-timezone': 'America/Los_Angeles',
      })

      const result = geo({ headers })

      expect(result.city).toBe('San Francisco')
      expect(result.countryCode).toBe('US')
      expect(result.country).toBe('United States')
      expect(result.region).toBe('CA')
      expect(result.latitude).toBe('37.7749')
      expect(result.longitude).toBe('-122.4194')
      expect(result.timezone).toBe('America/Los_Angeles')
    })

    it('should return undefined for missing headers', () => {
      const headers = new Headers()

      const result = geo({ headers })

      expect(result.city).toBeUndefined()
      expect(result.countryCode).toBeUndefined()
      expect(result.country).toBeUndefined()
      expect(result.region).toBeUndefined()
      expect(result.latitude).toBeUndefined()
      expect(result.longitude).toBeUndefined()
      expect(result.timezone).toBeUndefined()
    })
  })

  describe('geoFromHeaders()', () => {
    it('should extract geo from raw Headers', () => {
      const headers = new Headers({
        'x-vercel-ip-city': 'Tokyo',
        'x-vercel-ip-country': 'JP',
        'x-vercel-ip-country-region': '13',
        'x-vercel-ip-latitude': '35.6762',
        'x-vercel-ip-longitude': '139.6503',
        'x-vercel-ip-timezone': 'Asia/Tokyo',
      })

      const result = geoFromHeaders(headers)

      expect(result.city).toBe('Tokyo')
      expect(result.countryCode).toBe('JP')
      expect(result.country).toBe('Japan')
      expect(result.region).toBe('13')
      expect(result.latitude).toBe('35.6762')
      expect(result.longitude).toBe('139.6503')
      expect(result.timezone).toBe('Asia/Tokyo')
    })

    it('should fall back to Cloudflare cf-ipcountry header', () => {
      const headers = new Headers({
        'cf-ipcountry': 'DE',
      })

      const result = geoFromHeaders(headers)

      expect(result.countryCode).toBe('DE')
      expect(result.country).toBe('Germany')
    })

    it('should prefer Vercel header over Cloudflare header', () => {
      const headers = new Headers({
        'x-vercel-ip-country': 'US',
        'cf-ipcountry': 'DE',
      })

      const result = geoFromHeaders(headers)

      expect(result.countryCode).toBe('US')
      expect(result.country).toBe('United States')
    })

    it('should return undefined country for unknown countryCode', () => {
      const headers = new Headers({
        'x-vercel-ip-country': 'ZZ',
      })

      const result = geoFromHeaders(headers)

      expect(result.countryCode).toBe('ZZ')
      expect(result.country).toBeUndefined()
    })

    it('should look up country name from countryCode', () => {
      const codes: Record<string, string> = {
        US: 'United States',
        GB: 'United Kingdom',
        DE: 'Germany',
        FR: 'France',
        JP: 'Japan',
        CN: 'China',
        IN: 'India',
        BR: 'Brazil',
        AU: 'Australia',
        CA: 'Canada',
      }

      for (const [code, name] of Object.entries(codes)) {
        const headers = new Headers({
          'x-vercel-ip-country': code,
        })
        const result = geoFromHeaders(headers)
        expect(result.country).toBe(name)
      }
    })
  })

  describe('isInRegion()', () => {
    it('should return true when countryCode matches a region', () => {
      expect(isInRegion({ countryCode: 'US' }, ['US', 'CA'])).toBe(true)
    })

    it('should return false when countryCode does not match', () => {
      expect(isInRegion({ countryCode: 'JP' }, ['US', 'CA'])).toBe(false)
    })

    it('should be case-insensitive', () => {
      expect(isInRegion({ countryCode: 'us' }, ['US'])).toBe(true)
      expect(isInRegion({ countryCode: 'US' }, ['us'])).toBe(true)
      expect(isInRegion({ countryCode: 'Us' }, ['uS'])).toBe(true)
    })

    it('should return false when countryCode is undefined', () => {
      expect(isInRegion({}, ['US', 'CA'])).toBe(false)
    })
  })

  describe('geoDistance()', () => {
    it('should calculate distance between New York and London', () => {
      // New York: 40.7128, -74.0060
      // London: 51.5074, -0.1278
      const distance = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
      expect(distance).toBeGreaterThan(5520)
      expect(distance).toBeLessThan(5620)
    })

    it('should return 0 for the same point', () => {
      const distance = geoDistance('35.6762', '139.6503', '35.6762', '139.6503')
      expect(distance).toBe(0)
    })

    it('should handle negative coordinates', () => {
      // Sydney: -33.8688, 151.2093
      // Buenos Aires: -34.6037, -58.3816
      const distance = geoDistance(
        '-33.8688',
        '151.2093',
        '-34.6037',
        '-58.3816'
      )
      // ~11800 km approximately
      expect(distance).toBeGreaterThan(11700)
      expect(distance).toBeLessThan(11900)
    })
  })
})

